import React, { useEffect, useState } from "react";
import { api } from "../../api";
import "./ProductsPage.css";

export default function ProductsPage() {
    const [products, setProducts] = useState([]);
    const [loading, setLoading] = useState(true);
    const [modalOpen, setModalOpen] = useState(false);
    const [editingProduct, setEditingProduct] = useState(null);
    const [formData, setFormData] = useState({ name: '', category: '', price: '', stock: '', description: '' });

    useEffect(() => { loadProducts(); }, []);

    const loadProducts = async () => {
        try {
            const data = await api.getProducts();
            setProducts(data);
        } catch (err) { alert("Ошибка загрузки"); }
        finally { setLoading(false); }
    };

    const openCreate = () => {
        setEditingProduct(null);
        setFormData({ name: '', category: '', price: '', stock: '', description: '' });
        setModalOpen(true);
    };

    const openEdit = (product) => {
        setEditingProduct(product);
        setFormData({ ...product });
        setModalOpen(true);
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        try {
            if (editingProduct) {
                await api.updateProduct(editingProduct.id, formData);
            } else {
                await api.createProduct(formData);
            }
            loadProducts();
            setModalOpen(false);
        } catch (err) { alert("Ошибка сохранения"); }
    };

    const handleDelete = async (id) => {
        if (!window.confirm("Удалить товар?")) return;
        try {
            await api.deleteProduct(id);
            loadProducts();
        } catch (err) { alert("Ошибка удаления"); }
    };

    return (
        <div className="page">
            <header className="header"><h1>Интернет-магазин</h1></header>
            <main className="main">
                <button className="btn" onClick={openCreate}>+ Добавить товар</button>
                {loading ? <p>Загрузка...</p> : (
                    <div className="grid">
                        {products.map(p => (
                            <div key={p.id} className="card">
                                <h3>{p.name}</h3>
                                <p>Категория: {p.category}</p>
                                <p>Цена: {p.price} ₽</p>
                                <p>На складе: {p.stock}</p>
                                <p>{p.description}</p>
                                <div className="actions">
                                    <button onClick={() => openEdit(p)}>✏️</button>
                                    <button onClick={() => handleDelete(p.id)}>🗑️</button>
                                </div>
                            </div>
                        ))}
                    </div>
                )}
            </main>

            {modalOpen && (
                <div className="modal-backdrop" onClick={() => setModalOpen(false)}>
                    <div className="modal" onClick={e => e.stopPropagation()}>
                        <h2>{editingProduct ? "Редактировать" : "Новый товар"}</h2>
                        <form onSubmit={handleSubmit}>
                            <input placeholder="Название" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} required />
                            <input placeholder="Категория" value={formData.category} onChange={e => setFormData({...formData, category: e.target.value})} />
                            <input type="number" placeholder="Цена" value={formData.price} onChange={e => setFormData({...formData, price: e.target.value})} required />
                            <input type="number" placeholder="Количество" value={formData.stock} onChange={e => setFormData({...formData, stock: e.target.value})} />
                            <textarea placeholder="Описание" value={formData.description} onChange={e => setFormData({...formData, description: e.target.value})} />
                            <button type="submit">Сохранить</button>
                            <button type="button" onClick={() => setModalOpen(false)}>Отмена</button>
                        </form>
                    </div>
                </div>
            )}
        </div>
    );
}
